// FAZ 11 — DİAGNOSTİCS: Global hata izleme sistemi
// ═══════════════════════════════════════════════════════════
window.DIAG_LOG=[];
window.DIAG_PERF={startTs:Date.now(),renders:0,slowOps:[]};

// Önceki session hatalarını yükle
try{const prev=sessionStorage.getItem('eray-diag');if(prev)window.DIAG_LOG=JSON.parse(prev)||[]}catch(e){}

function diagPush(entry){
  window.DIAG_LOG.unshift(entry);
  if(window.DIAG_LOG.length>100)window.DIAG_LOG=window.DIAG_LOG.slice(0,100);
  try{sessionStorage.setItem('eray-diag',JSON.stringify(window.DIAG_LOG))}catch(e){}
}

// JavaScript hataları
window.onerror=function(msg,src,line,col,err){
  diagPush({ts:new Date().toLocaleString('tr-TR'),type:'🔴 JS Hatası',
    msg:String(msg),
    loc:(src?src.split('/').pop():'')+':'+line+':'+col,
    stack:err&&err.stack?err.stack.slice(0,800):''});
  return false};

// Promise hataları
window.onunhandledrejection=function(ev){
  diagPush({ts:new Date().toLocaleString('tr-TR'),type:'🟠 Promise Hatası',
    msg:ev.reason?(String(ev.reason.message||ev.reason)):'Bilinmeyen promise hatası',
    loc:'',stack:ev.reason&&ev.reason.stack?ev.reason.stack.slice(0,800):''})};

// Manuel iz bırakma fonksiyonu — kritik noktalarda çağrılır
function diagTrace(label,data){
  diagPush({ts:new Date().toLocaleString('tr-TR'),type:'🔵 İz',
    msg:label,loc:'',stack:data?JSON.stringify(data).slice(0,400):''})
}

// Render sayacı
function diagRender(){
  window.DIAG_PERF.renders++;
  window.DIAG_PERF.lastRender=new Date().toLocaleString('tr-TR')
}
