function getReyonOf(nm){const f=S.F.find(x=>x.n.toLowerCase()===nm.toLowerCase());if(f&&f.ct)return f.ct;const p=S.P.find(x=>x.n.toLowerCase()===nm.toLowerCase());if(p&&p.ct)return p.ct;return'Diğer'}
function reyonIdx(nm){const c=getReyonOf(nm);const i=REYON_ORDER.indexOf(c);return i<0?REYON_ORDER.length-1:i}
function isKilerItem(i){return i.ab==='Kiler'||i.ab==='🧹 Kiler'||i.loc==='kil'||S.P.some(p=>p.n.toLowerCase()===i.nm.toLowerCase())}
