const SEASONS={spring:['enginar','bezelye','çilek','bakla','marul','dereotu','roka','kuşkonmaz'],summer:['domates','patlıcan','biber','karpuz','kiraz','levrek','kabak','salatalık','mısır','şeftali'],autumn:['kabak','mantar','nar','ayva','palamut','kestane','hamsi','pancar','balkabağı'],winter:['lahana','ıspanak','kereviz','portakal','hamsi','turp','pırasa']};
function gSeas(){const m=new Date().getMonth();if(m>=2&&m<=4)return'spring';if(m>=5&&m<=7)return'summer';if(m>=8&&m<=10)return'autumn';return'winter'}
function isSeas(r){const s=SEASONS[gSeas()];return(r.ig||[]).some(ig=>s.some(sv=>ig.toLowerCase().includes(sv)))}
function seasLbl(){return{spring:'🌸 İlkbahar',summer:'☀️ Yaz',autumn:'🍂 Sonbahar',winter:'❄️ Kış'}[gSeas()]}
// TEKRAR KORUMASI
function recentR(){const now=new Date(),two=new Date(now);two.setDate(now.getDate()-14);const used=new Set();Object.entries(S.M||{}).forEach(([dt,m])=>{try{if(new Date(dt)>=two){if(m.k)used.add(m.k);if(m.a)used.add(m.a)}}catch{}});return used}
