function chkAch(id){if(!S.ACH)S.ACH=[];if(S.ACH.includes(id))return;S.ACH.push(id);sv('ACH');const a=ACHS.find(x=>x.id===id);if(a)setTimeout(()=>showAch(a),300)}
function showAch(a){const e=document.createElement('div');e.className='mo';e.onclick=()=>e.remove();e.innerHTML='<div class="md" onclick="event.stopPropagation()" style="text-align:center;padding:28px"><div style="font-size:52px;margin-bottom:8px;animation:bounce 1s infinite">'+a.ic+'</div><h3 style="color:var(--primary)">Yeni Rozet!</h3><div style="font-size:22px;font-weight:800;margin:8px 0">'+a.n+'</div><p style="color:var(--txtL);font-size:13px">'+a.d+'</p><div style="display:flex;gap:6px;margin-top:8px;justify-content:center"><span style="font-size:20px">🐕</span><span style="font-size:20px">🐈</span></div><button class="btn bp" style="margin-top:14px;max-width:180px;margin:14px auto 0" onclick="this.closest(\'.mo\').remove()">Harika! 🎉</button></div>';document.body.appendChild(e)}
// HAFTA KUTLAMASI
function kutla(){const e=document.createElement('div');e.className='mo';e.onclick=()=>e.remove();const q=['🎉','🎊','🏆','⭐','🌟'];const ic=q[Math.floor(Math.random()*q.length)];e.innerHTML='<div class="md" onclick="event.stopPropagation()" style="text-align:center;padding:28px"><div style="font-size:52px;margin-bottom:8px;animation:bounce 1s infinite">'+ic+'</div><h3 style="color:var(--mutfak)">Hafta Tamamlandı!</h3><p style="color:var(--txtL);font-size:13px;margin:8px 0">7 günlük menü planlandı! Bravo '+S.user+'!</p><div style="display:flex;gap:6px;margin-top:6px;justify-content:center"><span style="font-size:24px">🐕</span><span style="font-size:24px">🐈</span></div><button class="btn bm" style="margin-top:14px;max-width:180px;margin:14px auto 0" onclick="this.closest(\'.mo\').remove()">Teşekkürler! 🎉</button></div>';document.body.appendChild(e);chkAch('tam_hafta')}
