// Günlük otomatik damacana düşümü
function checkDamDaily(){
  const today=tISO();
  const last=S.D.lastDate||today;
  if(last>=today)return;
  // Geçen gün sayısı
  const diff=Math.floor((new Date(today)-new Date(last))/864e5);
  if(diff<=0)return;
  const rate=S.D.dailyRate!=null?S.D.dailyRate:20;
  const drop=diff*rate;
  S.D.l1=Math.max(0,Math.round((S.D.l1!=null?S.D.l1:80)-drop));
  S.D.l2=Math.max(0,Math.round((S.D.l2!=null?S.D.l2:60)-drop));
  S.D.lastDate=today;
  sv('D');
}
