// FAZ 11 — BİLDİRİM SİSTEMİ: Uygulama açılınca kontroller
function f11Bildirimler(){
if(sessionStorage.getItem('f11-notif'))return;sessionStorage.setItem('f11-notif','1');
const msgs=[];
// 1. Akşam yemeği planlandı mı? (saat ayarını geçtiyse)
const todayMenu=S.M[tISO()]||{};
if(!todayMenu.a&&!todayMenu.sp){
const nt=S.SE&&S.SE.nt?S.SE.nt:'17:00';const now=new Date();
const[h,m]=nt.split(':').map(Number);const nt2=new Date();nt2.setHours(h,m,0,0);
if(now>=nt2)msgs.push({msg:'🌙 Bugün için akşam yemeği henüz planlanmadı!',tp:'warn'})}
// 2. Stokta kalan 0 ürün
const sifir=[...S.F.filter(f=>f.cr<=0),...S.P.filter(p=>p.cr<=0)];
if(sifir.length>0)msgs.push({msg:'🧊 '+sifir.length+' ürün tamamen bitti! ('+sifir.slice(0,3).map(x=>x.n).join(', ')+(sifir.length>3?'...':'')+')',tp:'err'});
// 3. Pazar: menü hatırlatması
if(new Date().getDay()===0){const bos=gw(0).filter(d=>{const m=S.M[d.dt]||{};return!m.k||!m.a}).length;
if(bos>0)msgs.push({msg:'📅 Pazar günü! Bu hafta '+bos+' gün menüsüz.',tp:'info'})}
msgs.forEach((m,i)=>setTimeout(()=>toast(m.msg,m.tp,4500),800+i*5000))}
function go(s,t){S.scr=s;if(t)S.mt=t;rn()}
function pu(u){S.user=u;localStorage.setItem('eray-user',u||'');if(u){S.scr='home';S.LOG.unshift({u,a:'login',dt:new Date().toLocaleString('tr-TR'),d:u+' uygulamaya giriş yaptı'});if(S.LOG.length>300)S.LOG=S.LOG.slice(0,300);sv('LOG');diagTrace('Giriş',{user:u});setTimeout(f11Bildirimler,3500)}rn()}
function addLog(a,d){if(!S.LOG)S.LOG=[];S.LOG.unshift({u:S.user||'?',a,dt:new Date().toLocaleString('tr-TR'),d});if(S.LOG.length>300)S.LOG=S.LOG.slice(0,300);sv('LOG')}

